#!/usr/bin/env python3
"""Audit F.3: generate a diverse-content prompt corpus at 5 size buckets.

Output: data/audit-prompts/{bucket}/prompt-{NN}.txt  + manifest.json

Sizes target token counts roughly; tokenizer-specific drift is expected.
Content variety spans: factual prose, narrative, dialogue, technical
exposition, code, and a few intentionally-repetitive prompts (to test
attention behavior at unusual distributions).

Buckets:
  tiny  : ~5 tokens   — minimum-shape probes
  short : ~20 tokens  — small prefill, fits single ubatch easily
  medium: ~80 tokens  — typical chat-prefix size
  long  : ~200 tokens — paragraph-scale, where the bisection's failing case lives
  vlong : ~500 tokens — substantial context, multi-paragraph
  multi : ~1200 tokens — forces multi-ubatch at default ubatch_size=512
"""

import json
import os
import pathlib
import sys

OUT = pathlib.Path("data/audit-prompts")

