def main():
    if OUT.exists():
        print(f"refusing to overwrite existing {OUT}", file=sys.stderr)
        return 1
    OUT.mkdir(parents=True)
    manifest = []
    for bucket, prompts in TIERS.items():
        bucket_dir = OUT / bucket
        bucket_dir.mkdir()
        for i, text in enumerate(prompts):
            path = bucket_dir / f"prompt-{i:02d}.txt"
            path.write_text(text)
            char_count = len(text)
            # rough token estimate: ~4 chars per token for English
            est_tokens = max(1, char_count // 4)
            manifest.append({
                "bucket": bucket,
                "id": f"{bucket}-{i:02d}",
                "file": str(path.relative_to(OUT)),
                "char_count": char_count,
                "est_tokens": est_tokens,
            })
    (OUT / "manifest.json").write_text(json.dumps(manifest, indent=2))
    print(f"wrote {len(manifest)} prompts across {len(TIERS)} buckets to {OUT}/")
    print(f"manifest at {OUT}/manifest.json")
    return 0

if __name__ == "__main__":
    sys.exit(main())
